import requests
import json

url = "https/api.wandb.ai/graphql"
headers = {"Content-Type": "application/json"}

# Try to get the history as a string (it returns [String!]!)
query = """
{
  project(entityName: "mluo", name: "deepscaler-1.5b") {
    runs(first: 1, filters: "{\\"displayName\\":\\"deepscaler-1.5b-24k\\"}") {
      edges {
        node {
          name
          displayName
          history
        }
      }
    }
  }
}
"""

resp = requests.post("https://api.wandb.ai/graphql", json={"query": query}, headers=headers)
print(f"Status: {resp.status_code}")
data = resp.json()

# history is a list of JSON strings
try:
    runs = data["data"]["project"]["runs"]["edges"]
    for edge in runs:
        node = edge["node"]
        history = node.get("history", [])
        print(f"Run: {node['displayName']}")
        print(f"History entries: {len(history)}")

        best_score = -1
        best_step = -1

        for entry_str in history:
            entry = json.loads(entry_str)
            step = entry.get("_step")
            score = entry.get("val/test_score/")
            if score is not None:
                if score > best_score:
                    best_score = score
                    best_step = step

        print(f"Best val/test_score: {best_score} at step {best_step}")
except Exception as e:
    print(f"Error: {e}")
    print(json.dumps(data, indent=2)[:3000])
